# ============================================================
# CELL 5 — Parse Positions & Classify Moves
# ============================================================

def parse_position(pos):
    if not pos: return (None, None, None, None, None)
    pos = str(pos).strip()

    if TERMINAL_FORMAT == "CWIT":
        prefix = "Y-CWIT-"
        if not pos.startswith(prefix):
            return (None, None, None, None, None)

        suffix = pos[len(prefix):]       # Everything after Y-CWIT-

        if len(suffix) < 6:
            return (None, None, None, None, None)

        stack = suffix[:6]               # First 6 chars = stack (e.g. 1A003C)

        tier = None
        if len(suffix) == 8:
            try:
                tier = int(suffix[7])
            except ValueError:
                tier = None

        return (stack, stack, None, None, tier)

    elif TERMINAL_FORMAT == "CGSA":
        m = re.match(r'Y-CGSA-([A-Z0-9]+)\s+(\d+)\s+([A-Z]+)\s+(\d+)', pos)
        if m:
            block, bay, row, tier = m.groups()
            return (f"{block}-{bay}-{row}", block, bay, row, int(tier))

    elif TERMINAL_FORMAT == "STANDARD":
        m = re.match(r'Y-.*-([A-Z0-9]+?)(\d{2,4})([A-Z]|\d{2})[.]?(\d+)$', pos)
        if m:
            block, bay, row, tier = m.groups()
            return (f"{block}-{bay}-{row}", block, bay, row, int(tier))

    return (None, None, None, None, None)


parse_pos_schema = StructType([
    StructField("full_stack", StringType()),
    StructField("block",      StringType()),
    StructField("bay",        StringType()),
    StructField("row",        StringType()),
    StructField("tier",       IntegerType()),
])

parse_pos_udf = F.udf(parse_position, parse_pos_schema)

# ─── Apply Parsing & Classification ──────────────────────────
df_moves = df_moves \
    .withColumn("_pos",           parse_pos_udf(F.col("From_Position_Name"))) \
    .withColumn("full_stack",     F.col("_pos.full_stack")) \
    .withColumn("block",          F.col("_pos.block")) \
    .withColumn("bay",            F.col("_pos.bay")) \
    .withColumn("row",            F.col("_pos.row")) \
    .withColumn("tier",           F.col("_pos.tier")) \
    .drop("_pos") \
    .withColumn("is_load",        is_target_udf(F.col("Move_Kind"))) \
    .withColumn("is_shift",       is_shift_udf(F.col("Move_Kind"))) \
    .withColumn("Time_Completed", F.col("t_put"))

print(f"✅ Positions parsed | Terminal: {TERMINAL_FORMAT}")
df_moves.select(
    "mve_gkey", "Unit_Nbr", "Move_Kind",
    "From_Position_Name", "full_stack", "block", "bay", "row", "tier",
    "is_load", "is_shift"
).show(5, truncate=False)
